import * as vscode from 'vscode';
import * as path from 'path';
import * as fs from 'fs';
import { ActiveTask, CockpitEvent, CockpitSession, UNASSIGNED_TASK_ID } from '../types';
import { CockpitFileWatcher } from '../watchers/FileWatcher';
import { Shadow, ShadowManager } from '../services/ShadowManager';
import { SessionManager } from '../services/SessionManager';

type TreeItemType = SectionItem | TaskItem | EventItem | WorkItemNode | FilesChangedSection | ShadowFileItem | SessionsSection | SessionItem | UnassignedSessionsSection;

interface FrameworkTask {
  taskId: string;
  title: string;
  status: 'todo' | 'in_progress' | 'done';
  summary?: { total: number; done: number; in_progress: number; todo: number };
  workItems?: WorkItem[];
}

interface WorkItem {
  id: string;
  name: string;
  status: string;
  file?: string;
}

export class TaskTreeProvider implements vscode.TreeDataProvider<TreeItemType> {
  private _onDidChangeTreeData = new vscode.EventEmitter<TreeItemType | undefined>();
  readonly onDidChangeTreeData = this._onDidChangeTreeData.event;

  private activeTask: ActiveTask | null = null;
  private events: Map<string, CockpitEvent[]> = new Map();
  private workspaceRoot: string;

  constructor(
    private fileWatcher: CockpitFileWatcher,
    private shadowManager: ShadowManager,
    private sessionManager?: SessionManager
  ) {
    this.workspaceRoot = fileWatcher.getWorkspaceRoot();

    fileWatcher.onActiveTaskChanged(task => {
      this.activeTask = task;
      this.refresh();
    });

    fileWatcher.onEventAdded(event => {
      const existing = this.events.get(event.taskId) || [];
      existing.push(event);
      this.events.set(event.taskId, existing);
      this.refresh();
    });
  }

  refresh(): void {
    this._onDidChangeTreeData.fire(undefined);
  }

  getTreeItem(element: TreeItemType): vscode.TreeItem {
    return element;
  }

  async getChildren(element?: TreeItemType): Promise<TreeItemType[]> {
    if (!element) {
      return this.getSections();
    }

    if (element instanceof SectionItem) {
      return this.getTasksForSection(element.section);
    }

    if (element instanceof TaskItem) {
      return this.getTaskChildren(element);
    }

    if (element instanceof SessionsSection) {
      return this.getSessionsForTask(element.taskId);
    }

    if (element instanceof FilesChangedSection) {
      return this.getFilesForTask(element.taskId);
    }

    return [];
  }

  private async getSections(): Promise<SectionItem[]> {
    const sections: SectionItem[] = [];

    const inProgressCount = await this.countTasksInDir('in_progress');
    const todoCount = await this.countTasksInDir('todo');
    const doneCount = await this.countTasksInDir('done');

    if (inProgressCount > 0) {
      sections.push(new SectionItem('in_progress', inProgressCount));
    }
    if (todoCount > 0) {
      sections.push(new SectionItem('todo', todoCount));
    }
    if (doneCount > 0) {
      sections.push(new SectionItem('done', doneCount));
    }

    return sections;
  }

  private async countTasksInDir(status: string): Promise<number> {
    const dirPath = path.join(this.workspaceRoot, '.ai/tasks', status);
    try {
      const entries = await fs.promises.readdir(dirPath, { withFileTypes: true });
      return entries.filter(e => e.isDirectory()).length;
    } catch {
      return 0;
    }
  }

  private async getTasksForSection(section: 'in_progress' | 'todo' | 'done'): Promise<TaskItem[]> {
    const dirPath = path.join(this.workspaceRoot, '.ai/tasks', section);
    const items: TaskItem[] = [];

    try {
      const entries = await fs.promises.readdir(dirPath, { withFileTypes: true });

      for (const entry of entries) {
        if (!entry.isDirectory()) continue;

        const taskId = entry.name;
        const task = await this.readFrameworkTask(taskId, section);

        if (task) {
          const isActive = this.activeTask?.taskId === taskId;
          items.push(new TaskItem(task, isActive));
        }
      }
    } catch {
      // Directory doesn't exist
    }

    return items;
  }

  private async readFrameworkTask(taskId: string, status: string): Promise<FrameworkTask | null> {
    const statusPath = path.join(this.workspaceRoot, '.ai/tasks', status, taskId, 'status.yaml');

    try {
      const content = await fs.promises.readFile(statusPath, 'utf8');
      return this.parseStatusYaml(content, taskId, status as 'todo' | 'in_progress' | 'done');
    } catch {
      return {
        taskId,
        title: taskId,
        status: status as 'todo' | 'in_progress' | 'done'
      };
    }
  }

  private parseStatusYaml(content: string, taskId: string, status: 'todo' | 'in_progress' | 'done'): FrameworkTask {
    const lines = content.split('\n');
    let title = taskId;
    let summary = { total: 0, done: 0, in_progress: 0, todo: 0 };
    const workItems: WorkItem[] = [];

    let inSummary = false;
    let inWorkItems = false;
    let currentWorkItem: Partial<WorkItem> | null = null;

    for (const line of lines) {
      if (line.startsWith('title:')) {
        title = line.replace('title:', '').trim().replace(/^["']|["']$/g, '');
      }

      if (line.startsWith('summary:')) {
        inSummary = true;
        inWorkItems = false;
        continue;
      }

      if (line.startsWith('work_items:')) {
        inSummary = false;
        inWorkItems = true;
        continue;
      }

      if (inSummary && line.includes(':')) {
        const [key, val] = line.split(':').map(s => s.trim());
        if (key === 'total') summary.total = parseInt(val) || 0;
        if (key === 'done') summary.done = parseInt(val) || 0;
        if (key === 'in_progress') summary.in_progress = parseInt(val) || 0;
        if (key === 'todo') summary.todo = parseInt(val) || 0;
      }

      if (inWorkItems) {
        if (line.trim().startsWith('- id:')) {
          if (currentWorkItem?.id) {
            workItems.push(currentWorkItem as WorkItem);
          }
          currentWorkItem = { id: line.split(':')[1]?.trim().replace(/["']/g, '') };
        } else if (currentWorkItem && line.includes('name:')) {
          currentWorkItem.name = line.split('name:')[1]?.trim().replace(/["']/g, '');
        } else if (currentWorkItem && line.includes('status:')) {
          currentWorkItem.status = line.split('status:')[1]?.trim();
        } else if (currentWorkItem && line.includes('file:')) {
          currentWorkItem.file = line.split('file:')[1]?.trim().replace(/["']/g, '');
        }
      }
    }

    if (currentWorkItem?.id) {
      workItems.push(currentWorkItem as WorkItem);
    }

    return { taskId, title, status, summary, workItems };
  }

  private async getTaskChildren(task: TaskItem): Promise<TreeItemType[]> {
    const items: TreeItemType[] = [];

    // Add Sessions section if sessions exist
    if (this.sessionManager) {
      const sessions = await this.sessionManager.getSessionsForTask(task.taskId);
      if (sessions.length > 0) {
        items.push(new SessionsSection(task.taskId, sessions.length));
      }
    }

    // Add work items if available
    if (task.task.workItems && task.task.workItems.length > 0) {
      for (const wi of task.task.workItems) {
        items.push(new WorkItemNode(wi, task.task.taskId, task.task.status));
      }
    }

    // Add Files Changed section if shadows exist
    const shadows = await this.shadowManager.getShadowsForTask(task.taskId);
    if (shadows.length > 0) {
      items.push(new FilesChangedSection(task.taskId, shadows.length));
    }

    return items;
  }

  private async getSessionsForTask(taskId: string): Promise<SessionItem[]> {
    if (!this.sessionManager) return [];

    const sessions = await this.sessionManager.getSessionsForTask(taskId);

    // Sort: active sessions first, then by lastActive descending
    return sessions
      .sort((a, b) => {
        if (a.status !== b.status) {
          return a.status === 'active' ? -1 : 1;
        }
        return new Date(b.lastActive).getTime() - new Date(a.lastActive).getTime();
      })
      .map(s => new SessionItem(s));
  }

  private async getFilesForTask(taskId: string): Promise<ShadowFileItem[]> {
    const shadows = await this.shadowManager.getShadowsForTask(taskId);
    const items: ShadowFileItem[] = [];

    for (const shadow of shadows) {
      const syncStatus = await this.shadowManager.checkSyncStatus(shadow);
      items.push(new ShadowFileItem(shadow, syncStatus));
    }

    // Sort: modified first, then by filename
    items.sort((a, b) => {
      if (a.syncStatus !== b.syncStatus) {
        if (a.syncStatus === 'user-modified') return -1;
        if (b.syncStatus === 'user-modified') return 1;
      }
      return a.shadow.meta.filePath.localeCompare(b.shadow.meta.filePath);
    });

    return items;
  }
}

class SectionItem extends vscode.TreeItem {
  constructor(
    public readonly section: 'in_progress' | 'todo' | 'done',
    count: number
  ) {
    const labels: Record<string, string> = {
      'in_progress': 'In Progress',
      'todo': 'Todo',
      'done': 'Done'
    };

    super(labels[section], vscode.TreeItemCollapsibleState.Expanded);

    this.description = `${count}`;
    this.contextValue = `section-${section}`;

    const icons: Record<string, string> = {
      'in_progress': 'play-circle',
      'todo': 'circle-outline',
      'done': 'check-all'
    };

    const colors: Record<string, string> = {
      'in_progress': 'charts.green',
      'todo': 'charts.yellow',
      'done': 'charts.blue'
    };

    this.iconPath = new vscode.ThemeIcon(icons[section], new vscode.ThemeColor(colors[section]));
  }
}

class TaskItem extends vscode.TreeItem {
  public readonly taskId: string;

  constructor(
    public readonly task: FrameworkTask,
    public readonly isActive: boolean
  ) {
    super(task.title, vscode.TreeItemCollapsibleState.Collapsed);

    this.taskId = task.taskId;
    this.id = task.taskId;

    // Show progress in description
    if (task.summary && task.summary.total > 0) {
      this.description = `${task.taskId} (${task.summary.done}/${task.summary.total})`;
    } else {
      this.description = task.taskId;
    }

    this.tooltip = `${task.taskId}: ${task.title}`;

    if (isActive) {
      this.iconPath = new vscode.ThemeIcon('play-circle', new vscode.ThemeColor('charts.green'));
      this.tooltip += '\n(Active)';
    } else {
      switch (task.status) {
        case 'done':
          this.iconPath = new vscode.ThemeIcon('check');
          break;
        case 'in_progress':
          this.iconPath = new vscode.ThemeIcon('circle-large-outline');
          break;
        default:
          this.iconPath = new vscode.ThemeIcon('circle-outline');
      }
    }

    this.contextValue = isActive ? 'task-active' : `task-${task.status}`;

    // Click to open task README
    this.command = {
      command: 'aiCockpit.openTask',
      title: 'View Task',
      arguments: [{ taskId: task.taskId, status: task.status, title: task.title }]
    };
  }
}

class WorkItemNode extends vscode.TreeItem {
  constructor(workItem: WorkItem, taskId: string, taskStatus: string) {
    super(workItem.name, vscode.TreeItemCollapsibleState.None);

    this.description = workItem.id;

    switch (workItem.status) {
      case 'done':
        this.iconPath = new vscode.ThemeIcon('check', new vscode.ThemeColor('charts.green'));
        break;
      case 'in_progress':
        this.iconPath = new vscode.ThemeIcon('sync~spin', new vscode.ThemeColor('charts.yellow'));
        break;
      default:
        this.iconPath = new vscode.ThemeIcon('circle-outline');
    }

    this.contextValue = `workitem-${workItem.status}`;

    // Click to open work item file
    this.command = {
      command: 'aiCockpit.openWorkItem',
      title: 'View Work Item',
      arguments: [{
        taskId: taskId,
        taskStatus: taskStatus,
        workItem: workItem
      }]
    };
  }
}

class EventItem extends vscode.TreeItem {
  constructor(
    public readonly eventId: string,
    public readonly tool: string,
    public readonly filePath: string,
    public readonly timestamp: string,
    public readonly event: CockpitEvent
  ) {
    super(path.basename(filePath), vscode.TreeItemCollapsibleState.None);

    this.id = eventId;
    this.description = this.formatTime(timestamp);
    this.tooltip = `${tool}: ${filePath}\n${timestamp}`;

    switch (tool) {
      case 'Edit':
        this.iconPath = new vscode.ThemeIcon('edit');
        break;
      case 'Write':
        this.iconPath = new vscode.ThemeIcon('new-file');
        break;
      case 'TodoWrite':
        this.iconPath = new vscode.ThemeIcon('checklist');
        break;
      default:
        this.iconPath = new vscode.ThemeIcon('file');
    }

    this.command = {
      command: 'aiCockpit.viewEventDiff',
      title: 'View Diff',
      arguments: [this.event]
    };

    this.contextValue = 'event';
  }

  private formatTime(timestamp: string): string {
    const date = new Date(timestamp);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
}

class FilesChangedSection extends vscode.TreeItem {
  constructor(public readonly taskId: string, fileCount: number) {
    super('Files Changed', vscode.TreeItemCollapsibleState.Collapsed);

    this.description = `${fileCount}`;
    this.iconPath = new vscode.ThemeIcon('files');
    this.contextValue = 'files-changed-section';
  }
}

class ShadowFileItem extends vscode.TreeItem {
  constructor(
    public readonly shadow: Shadow,
    public readonly syncStatus: 'synced' | 'user-modified' | 'file-deleted'
  ) {
    super(
      path.basename(shadow.meta.filePath),
      vscode.TreeItemCollapsibleState.None
    );

    this.description = `${shadow.meta.accumulated.editCount} edit${shadow.meta.accumulated.editCount !== 1 ? 's' : ''}`;
    this.tooltip = `${shadow.meta.filePath}\n${shadow.meta.accumulated.editCount} Claude edits\nStatus: ${syncStatus}`;

    // Icon based on sync status
    switch (syncStatus) {
      case 'synced':
        this.iconPath = new vscode.ThemeIcon('check', new vscode.ThemeColor('charts.green'));
        break;
      case 'user-modified':
        this.iconPath = new vscode.ThemeIcon('warning', new vscode.ThemeColor('charts.yellow'));
        this.description += ' (modified)';
        break;
      case 'file-deleted':
        this.iconPath = new vscode.ThemeIcon('trash', new vscode.ThemeColor('charts.red'));
        this.description += ' (deleted)';
        break;
    }

    // Click to show full diff
    this.command = {
      command: 'aiCockpit.showFullDiff',
      title: 'Show Full Diff',
      arguments: [shadow]
    };

    this.contextValue = `shadow-file-${syncStatus}`;
  }
}

class SessionsSection extends vscode.TreeItem {
  constructor(
    public readonly taskId: string,
    sessionCount: number
  ) {
    super('Sessions', vscode.TreeItemCollapsibleState.Collapsed);

    // Set id to taskId so it's preserved when VSCode serializes the TreeItem
    this.id = `sessions-${taskId}`;
    this.description = `${sessionCount}`;
    this.iconPath = new vscode.ThemeIcon('terminal');
    this.contextValue = 'sessions-section';
  }
}

class SessionItem extends vscode.TreeItem {
  constructor(public readonly session: CockpitSession) {
    super(session.label, vscode.TreeItemCollapsibleState.None);

    this.description = session.status;

    // Icon: green circle for active, gray outline for closed
    if (session.status === 'active') {
      this.iconPath = new vscode.ThemeIcon(
        'circle-filled',
        new vscode.ThemeColor('charts.green')
      );
    } else {
      this.iconPath = new vscode.ThemeIcon('circle-outline');
    }

    // Click behavior depends on session status
    if (session.status === 'active') {
      this.command = {
        command: 'aiCockpit.focusSession',
        title: 'Focus Session',
        arguments: [session]
      };
    } else {
      this.command = {
        command: 'aiCockpit.resumeSession',
        title: 'Resume Session',
        arguments: [session]
      };
    }

    this.contextValue = `session-${session.status}`;

    // Format timestamps for tooltip
    const created = new Date(session.createdAt).toLocaleString();
    const lastActive = new Date(session.lastActive).toLocaleString();
    this.tooltip = `Session ID: ${session.id}\nCreated: ${created}\nLast active: ${lastActive}`;
  }
}
